const body = $input.all()[0].json;
const files = $input.all()[0].binary || {};
const fileKey = Object.keys(files)[0];
if (!fileKey) throw new Error('No file attached. POST with multipart/form-data: file=<PDF or image>');
return [{ json: { fileKey, vendor_hint: body.vendor_name || '', entity_id: body.entity_id || 1 }, binary: files }];

// Parse Mindee OCR response into structured invoice data
const ocr = $input.all()[0].json;
const prediction = ocr?.document?.inference?.prediction || {};

const fmt = (field) => field?.value || null;
const fmtAmount = (field) => field?.value ? parseFloat(field.value) : 0;

const vendor     = fmt(prediction.supplier_name)       || $('Validate Upload').all()[0].json.vendor_hint || 'Unknown Vendor';
const invoice_no = fmt(prediction.invoice_number)      || 'OCR-' + Date.now();
const inv_date   = fmt(prediction.date)                || new Date().toISOString().split('T')[0];
const due_date   = fmt(prediction.due_date)            || null;
const total_net  = fmtAmount(prediction.total_net);
const total_tax  = fmtAmount(prediction.total_tax);
const total_incl = fmtAmount(prediction.total_amount)  || (total_net + total_tax);
const currency   = fmt(prediction.locale?.currency)    || 'NGN';

// Determine WHT code from vendor/line items (heuristic)
const desc_raw   = (prediction.line_items || []).map(l => l.description || '').join(' ').toLowerCase();
let wht_code = 'NG-WHT-SUP'; // default
if (desc_raw.includes('legal') || desc_raw.includes('audit') || desc_raw.includes('tax')) wht_code = 'NG-WHT-PRF';
else if (desc_raw.includes('consult') || desc_raw.includes('manage') || desc_raw.includes('service')) wht_code = 'NG-WHT-TEC';
else if (desc_raw.includes('rent') || desc_raw.includes('lease')) wht_code = 'NG-WHT-RNT';
else if (desc_raw.includes('construct') || desc_raw.includes('build') || desc_raw.includes('civil')) wht_code = 'NG-WHT-CON';

// Calculate WHT
const WHT_RATES = { 'NG-WHT-SUP':0.05,'NG-WHT-PRF':0.10,'NG-WHT-TEC':0.10,'NG-WHT-RNT':0.10,'NG-WHT-CON':0.025 };
const wht_rate   = WHT_RATES[wht_code] || 0.05;
const wht_amount = parseFloat((total_net * wht_rate).toFixed(2));
const net_payable = parseFloat((total_net - wht_amount).toFixed(2));

// VAT check (NTA 2025: 7.5%)
const expected_vat = parseFloat((total_net * 0.075).toFixed(2));
const vat_variance = parseFloat(Math.abs(total_tax - expected_vat).toFixed(2));

return [{ json: {
  ocr_confidence: ocr?.document?.n_pages > 0 ? 'OK' : 'LOW',
  vendor_name:    vendor,
  invoice_number: invoice_no,
  invoice_date:   inv_date,
  due_date,
  currency,
  total_net,
  total_tax,
  total_incl,
  wht_code,
  wht_rate:       (wht_rate * 100).toFixed(1) + '%',
  wht_amount,
  net_payable,
  expected_vat,
  vat_variance,
  vat_ok:         vat_variance < 100,
  staged_for_review: vat_variance >= 100 || total_net <= 0,
  entity_id:      $('Validate Upload').all()[0].json.entity_id
} }];
